import styles from '../styles/accordion.module.css';
import { AccordionProps, AccordionItem } from '../types/components';

export const Accordion: React.FC<AccordionProps> = ({
  items,
  defaultExpanded = [],
  allowMultiple = false,
}) => {
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set(defaultExpanded));
  const triggerRefs = useRef<(HTMLButtonElement | null)[]>([]);

  const toggleItem = useCallback((id: string) => {
    setExpandedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        if (!allowMultiple) {
          next.clear();
        }
        next.add(id);
      }
      return next;
    });
  }, [allowMultiple]);

  const handleKeyDown = useCallback((event: KeyboardEvent<HTMLButtonElement>, currentIndex: number) => {
    const totalItems = items.length;
    let nextIndex: number | null = null;

    switch (event.key) {
      case 'ArrowDown':
        event.preventDefault();
        nextIndex = (currentIndex + 1) % totalItems;
        break;
      case 'ArrowUp':
        event.preventDefault();
        nextIndex = (currentIndex - 1 + totalItems) % totalItems;
        break;
      case 'Home':
        event.preventDefault();
        nextIndex = 0;
        break;
      case 'End':
        event.preventDefault();
        nextIndex = totalItems - 1;
        break;
      case 'Enter':
      case ' ':
        event.preventDefault();
        toggleItem(items[currentIndex].id);
        return;
      default:
        return;
    }

    if (nextIndex !== null && triggerRefs.current[nextIndex]) {
      triggerRefs.current[nextIndex]!.focus();
    }
  }, [items, toggleItem]);

  return (
    <div className={styles.accordion} role="accordion">
      {items.map((item: AccordionItem, index: number) => {
        const isExpanded = expandedIds.has(item.id);
        const panelId = `accordion-panel-${item.id}`;
        const triggerId = `accordion-trigger-${item.id}`;

        return (
          <div key={item.id} className={styles.accordionItem}>
            <button
              id={triggerId}
              className={styles.accordionTrigger}
              onClick={() => toggleItem(item.id)}
              onKeyDown={(e) => handleKeyDown(e, index)}
              aria-expanded={isExpanded}
              aria-controls={panelId}
              tabIndex={isExpanded ? 0 : -1}
              ref={(el) => { triggerRefs.current[index] = el; }}
            >
              {item.trigger}
              <span className={`${styles.accordionIcon} ${isExpanded ? styles.accordionIconExpanded : ''}`}>
                ▼
              </span>
            </button>
            <div
              id={panelId}
              className={styles.accordionPanel}
              role="region"
              aria-labelledby={triggerId}
              hidden={!isExpanded}
            >
              {item.content}
            </div>
          </div>
        );
      })}
    </div>
  );
};

