import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { Accordion } from './Accordion';
import { AccordionItem } from '../types/components';

const testItems: AccordionItem[] = [
  { id: 'item-1', trigger: 'First Section', content: 'Content for first section' },
  { id: 'item-2', trigger: 'Second Section', content: 'Content for second section' },
  { id: 'item-3', trigger: 'Third Section', content: 'Content for third section' },
];

describe('Accordion', () => {
  describe('Keyboard Navigation', () => {
    it('moves focus to next trigger on ArrowDown', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} />);

      const triggers = screen.getAllByRole('button');
      triggers[0].focus();

      await user.keyboard('{ArrowDown}');

      expect(document.activeElement).toBe(triggers[1]);
    });

    it('moves focus to previous trigger on ArrowUp', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} />);

      const triggers = screen.getAllByRole('button');
      triggers[2].focus();

      await user.keyboard('{ArrowUp}');

      expect(document.activeElement).toBe(triggers[1]);
    });

    it('jumps to first trigger on Home', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} />);

      const triggers = screen.getAllByRole('button');
      triggers[2].focus();

      await user.keyboard('{Home}');

      expect(document.activeElement).toBe(triggers[0]);
    });

    it('jumps to last trigger on End', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} />);

      const triggers = screen.getAllByRole('button');
      triggers[0].focus();

      await user.keyboard('{End}');

      expect(document.activeElement).toBe(triggers[2]);
    });

    it('activates a trigger on Enter', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} />);

      const firstTrigger = screen.getAllByRole('button')[0];
      firstTrigger.focus();

      await user.keyboard('{Enter}');

      expect(firstTrigger).toHaveAttribute('aria-expanded', 'true');
    });
  });

  describe('ARIA State', () => {
    it('toggles aria-expanded on trigger activation', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} />);

      const firstTrigger = screen.getAllByRole('button')[0];

      expect(firstTrigger).toHaveAttribute('aria-expanded', 'false');

      await user.click(firstTrigger);

      expect(firstTrigger).toHaveAttribute('aria-expanded', 'true');
    });

    it('has aria-controls pointing to panel ID', () => {
      render(<Accordion items={testItems} />);

      const firstTrigger = screen.getAllByRole('button')[0];

      expect(firstTrigger).toHaveAttribute('aria-controls', 'accordion-panel-item-1');
    });
  });

  describe('Focus Management', () => {
    it('focus remains on trigger after activation', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} />);

      const firstTrigger = screen.getAllByRole('button')[0];
      firstTrigger.focus();

      await user.click(firstTrigger);

      expect(document.activeElement).toBe(firstTrigger);
    });

    it('uses roving tabindex pattern', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} />);

      const triggers = screen.getAllByRole('button');

      // First trigger should be tabbable (tabIndex=0)
      expect(triggers[0]).toHaveAttribute('tabIndex', '0');
      // Others should not (tabIndex=-1)
      expect(triggers[1]).toHaveAttribute('tabIndex', '-1');
      expect(triggers[2]).toHaveAttribute('tabIndex', '-1');

      // Click second trigger to expand it
      await user.click(triggers[1]);

      // After expansion, second trigger should be tabbable
      expect(triggers[1]).toHaveAttribute('tabIndex', '0');
      // First should now be -1
      expect(triggers[0]).toHaveAttribute('tabIndex', '-1');
    });
  });

  describe('Content Panel Visibility', () => {
    it('toggles content panel visibility on trigger activation', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} />);

      const firstTrigger = screen.getAllByRole('button')[0];
      const firstPanel = screen.getByText('Content for first section');

      // Panel should be hidden initially
      expect(firstPanel).not.toBeVisible();

      await user.click(firstTrigger);

      // Panel should be visible after click
      expect(firstPanel).toBeVisible();
    });

    it('hides content when trigger is deactivated', async () => {
      const user = userEvent.setup();
      render(<Accordion items={testItems} defaultExpanded={['item-1']} />);

      const firstTrigger = screen.getAllByRole('button')[0];
      const firstPanel = screen.getByText('Content for first section');

      // Panel should be visible initially
      expect(firstPanel).toBeVisible();

      await user.click(firstTrigger);

      // Panel should be hidden after click
      expect(firstPanel).not.toBeVisible();
    });
  });
});","filePath":"/home/zzwf/shared/agent-container/workspace/RL/just-oc/autoresearch/test/frontend_developer_worker/run-20260408-215439-1/src/components/Accordion.test.tsx"},"output":"Wrote file successfully.","metadata":{"diagnostics":{},"filepath":"/home/zzwf/shared/agent-container/workspace/RL/just-oc/autoresearch/test/frontend_developer_worker/run-20260408-215439-1/src/components/Accordion.test.tsx","exists":false,"truncated":false},"title":"autoresearch/test/frontend_developer_worker/run-20260408-215439-1/src/components/Accordion.test.tsx","time":{"start":1775685477618,"end":1775685477635}}}}

